query:
UPDATE articles 
SET content = REPLACE(
  REPLACE(
    REPLACE(
      REPLACE(
        REPLACE(content, 'Best Best Best Best Best ', 'Best '),
        'Best Best Best Best ', 'Best '
      ),
      'Best Best Best ', 'Best '
    ),
    'Best Best ', 'Best '
  ),
  'best best ', 'best '
)
WHERE content LIKE '%Best Best%' OR content LIKE '%best best%';

